package main

import (
	"fmt"
	"math"
)

func main() {
	// Sqrt
	fmt.Println("sqrt(144):", math.Sqrt(144))

	// Abs
	fmt.Println("abs(-42):", math.Abs(-42))

	// Floor and Ceil
	fmt.Println("floor(3.7):", math.Floor(3.7))
	fmt.Println("ceil(3.2):", math.Ceil(3.2))

	// Pi constant
	fmt.Println("pi:", math.Pi)
}
